#include <bits/stdc++.h>
using namespace std;
struct thun{
    int l,r;
}a[1000006];
bool cmp(thun n1,thun n2){
    if(n1.l==n2.l)return n1.r>n2.r;
    return n1.l<n2.l;
}
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        cin>>a[i].l;
        a[i].r=a[i].l+2;
        a[i].l-=2;
        if(a[i].l<0)a[i].l=0;
        if(a[i].r>n)a[i].r=n;
    }
    int ans=0,now=1;
    sort(a+1,a+m+1,cmp);
    for(int i=1;i<=m;i++){
        if(a[i].l>now)now=a[i].l;
        if(a[i].r>=now){
            ans+=a[i].r-now+1;
            now=a[i].r+1;
        }
    }
    cout<<ans;
    return 0;
}
